-- ================================================================
-- RoadWatch Database Dump
-- AI-Powered Road Safety and Transparency Platform
-- IIT Madras National Road Safety Hackathon 2026
-- ================================================================
-- Tables: roads, complaints, authorities, budget_records
-- Roads: 35 | Countries: 13 | Authorities: 37 | Complaints: 21
-- ================================================================

BEGIN TRANSACTION;
CREATE TABLE authorities (
	id INTEGER NOT NULL, 
	country VARCHAR, 
	state VARCHAR, 
	district VARCHAR, 
	road_type VARCHAR, 
	department VARCHAR, 
	name VARCHAR, 
	designation VARCHAR, 
	email VARCHAR, 
	phone VARCHAR, 
	office_address VARCHAR, 
	PRIMARY KEY (id)
);
CREATE TABLE budget_records (
	id INTEGER NOT NULL, 
	road_id INTEGER, 
	financial_year VARCHAR, 
	work_type VARCHAR, 
	amount_sanctioned FLOAT, 
	amount_spent FLOAT, 
	currency VARCHAR, 
	contractor VARCHAR, 
	work_start VARCHAR, 
	work_end VARCHAR, 
	source_url VARCHAR, 
	source_label VARCHAR, 
	verified BOOLEAN, 
	PRIMARY KEY (id), 
	FOREIGN KEY(road_id) REFERENCES roads (id)
);
CREATE TABLE complaints (
	id INTEGER NOT NULL, 
	complaint_id VARCHAR, 
	road_id INTEGER, 
	citizen_name VARCHAR, 
	phone VARCHAR, 
	email VARCHAR, 
	country VARCHAR, 
	state VARCHAR, 
	issue_type VARCHAR, 
	description TEXT, 
	severity VARCHAR, 
	image_path VARCHAR, 
	ai_assessment TEXT, 
	location_lat FLOAT, 
	location_lon FLOAT, 
	location_desc VARCHAR, 
	routed_to_name VARCHAR, 
	routed_to_email VARCHAR, 
	routed_to_phone VARCHAR, 
	department VARCHAR, 
	status VARCHAR, 
	resolution_note TEXT, 
	filed_at DATETIME, 
	updated_at DATETIME, 
	resolved_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(road_id) REFERENCES roads (id)
);
CREATE TABLE roads (
	id INTEGER NOT NULL, 
	road_id VARCHAR, 
	road_name VARCHAR, 
	road_type VARCHAR, 
	country VARCHAR, 
	state VARCHAR, 
	district VARCHAR, 
	contractor_name VARCHAR, 
	contractor_contact VARCHAR, 
	executive_engineer VARCHAR, 
	ee_email VARCHAR, 
	ee_phone VARCHAR, 
	department VARCHAR, 
	total_length_km FLOAT, 
	construction_date VARCHAR, 
	last_relayed_date VARCHAR, 
	next_maintenance VARCHAR, 
	surface_type VARCHAR, 
	condition_score FLOAT, 
	condition_label VARCHAR, 
	budget_sanctioned FLOAT, 
	budget_spent FLOAT, 
	currency VARCHAR, 
	financial_year VARCHAR, 
	data_source VARCHAR, 
	data_source_label VARCHAR, 
	lat_start FLOAT, 
	lon_start FLOAT, 
	lat_end FLOAT, 
	lon_end FLOAT, 
	lat_center FLOAT, 
	lon_center FLOAT, 
	created_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE INDEX ix_roads_road_name ON roads (road_name);
CREATE UNIQUE INDEX ix_roads_road_id ON roads (road_id);
CREATE INDEX ix_roads_id ON roads (id);
CREATE INDEX ix_authorities_id ON authorities (id);
CREATE INDEX ix_budget_records_id ON budget_records (id);
CREATE UNIQUE INDEX ix_complaints_complaint_id ON complaints (complaint_id);
CREATE INDEX ix_complaints_id ON complaints (id);
COMMIT;
